import { usePosts } from "../hooks/usePosts";

const ImageGrid = () => {
  const posts = usePosts();

  return (
    <div className="img-grid">
      {posts.map((post) => (
        <div className="img-wrap" key={post.id}>
          <img src={post.image_url} alt="" />
        </div>
      ))}
    </div>
  );
};

export default ImageGrid;
